// Description: Discovers Nexus scheduled tasks via the tasks REST API.
// Description: Each task becomes a monitored instance with task type as a grouping property.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("nexus.host")
def user = hostProps.get("nexus.user")
def pass = hostProps.get("nexus.pass")
def port = hostProps.get("nexus.port") ?: "8081"
def useSsl = (hostProps.get("nexus.ssl") ?: "true").toLowerCase() == "true"

if (!host || !user || !pass) {
    return 1
}

def credentials = "${user}:${pass}".bytes.encodeBase64().toString()

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def allTasks = []
def continuationToken = null

// Paginate through all tasks
while (true) {
    try {
        def path = "/service/rest/v1/tasks"
        if (continuationToken) {
            path += "?continuationToken=${java.net.URLEncoder.encode(continuationToken, 'UTF-8')}"
        }
        def url = new URL("${baseUrl}${path}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Basic ${credentials}")
        conn.setRequestProperty("Accept", "application/json")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)

        if (conn.responseCode == 200) {
            def response = new JsonSlurper().parseText(conn.inputStream.text)
            def items = response.items ?: []
            allTasks.addAll(items)
            continuationToken = response.continuationToken
            if (!continuationToken) break
        } else {
            System.err.println("Task discovery failed: HTTP ${conn.responseCode}")
            return 1
        }
    } catch (Exception e) {
        System.err.println("Task discovery error: ${e.message}")
        return 1
    }
}

allTasks.each { task ->
    def id = task.id ?: "unknown"
    def name = task.name ?: "unknown"
    def type = task.type ?: "unknown"
    println "${id}##${name}##${type} task####auto.task.name=${java.net.URLEncoder.encode(name, 'UTF-8')}&auto.task.type=${java.net.URLEncoder.encode(type, 'UTF-8')}"
}
return 0

